    |> assign(:session, session)
    |> register_before_send(fn conn ->
      session = conn.assigns[:session] || SessionManager.new()
      serialized = SessionManager.serialize(session)
      put_resp_cookie(conn, cookie_name, serialized, cookie_opts)
    end)
  end
